import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.BYehg5q7.js";const g=JSON.parse('{"title":"OpenClaw","description":"","frontmatter":{},"headers":[],"relativePath":"guide/openclaw.md","filePath":"guide/openclaw.md","lastUpdated":1774954986000}'),i={name:"guide/openclaw.md"};function o(l,e,r,h,c,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="openclaw" tabindex="-1">OpenClaw <a class="header-anchor" href="#openclaw" aria-label="Permalink to &quot;OpenClaw&quot;">​</a></h1><p><a href="https://openclaw.ai" target="_blank" rel="noreferrer">OpenClaw</a> is a self-hosted AI assistant you can connect to any messenger (Telegram, Signal, Discord, etc.). It connects to getbased via <a href="https://github.com/elkimek/getbased-mcp" target="_blank" rel="noreferrer">getbased-mcp</a>, letting your OpenClaw bot answer questions about your blood work — &quot;what&#39;s my vitamin D trend?&quot; or &quot;summarize my last labs&quot; — directly in chat.</p><p>Only a read-only summary is shared. Your raw data and sync mnemonic never leave your browser.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>getbased (browser) → Context Gateway ← getbased-mcp ← OpenClaw bot</span></span></code></pre></div><ol><li>You enable <strong>Agent Access</strong> in getbased and get a read-only token</li><li>getbased pushes a text summary of your labs, context cards, supplements, and goals to the context gateway</li><li>Your OpenClaw bot uses getbased-mcp with the token to read that summary and answer questions</li></ol><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="_1-enable-in-getbased" tabindex="-1">1. Enable in getbased <a class="header-anchor" href="#_1-enable-in-getbased" aria-label="Permalink to &quot;1. Enable in getbased&quot;">​</a></h3><p>Go to <strong>Settings → Data → Agent Access</strong> and toggle it on. A read-only token is generated.</p><h3 id="_2-install-getbased-mcp" tabindex="-1">2. Install getbased-mcp <a class="header-anchor" href="#_2-install-getbased-mcp" aria-label="Permalink to &quot;2. Install getbased-mcp&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/elkimek/getbased-mcp.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> getbased-mcp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><h3 id="_3-configure-openclaw" tabindex="-1">3. Configure OpenClaw <a class="header-anchor" href="#_3-configure-openclaw" aria-label="Permalink to &quot;3. Configure OpenClaw&quot;">​</a></h3><p>Add getbased-mcp as an MCP server in your OpenClaw config with your token and gateway URL.</p><h3 id="_4-chat" tabindex="-1">4. Chat <a class="header-anchor" href="#_4-chat" aria-label="Permalink to &quot;4. Chat&quot;">​</a></h3><p>Ask your bot anything about your labs. The MCP server provides three tools the AI can use:</p><ul><li><strong>getbased_lab_context</strong> — full lab summary with values, ranges, trends, context cards, supplements, and goals</li><li><strong>getbased_section</strong> — query a specific section (hormones, biometrics, etc.) or list available sections</li><li><strong>getbased_list_profiles</strong> — list all profiles (if you track multiple people)</li></ul><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li>The token grants <strong>read-only</strong> access to a pre-built text summary</li><li>Your sync mnemonic is never shared</li><li>Revoking the token (toggle off or regenerate) immediately cuts access</li><li>The context gateway runs on the same server as the sync relay — self-host both for full control</li></ul><h2 id="self-hosting" tabindex="-1">Self-Hosting <a class="header-anchor" href="#self-hosting" aria-label="Permalink to &quot;Self-Hosting&quot;">​</a></h2><p>The context gateway is a lightweight Node.js server. If you <a href="./cross-device-sync.html#running-your-own-relay">self-host your sync relay</a>, the gateway runs alongside it on the same VPS.</p>`,20)])])}const u=a(i,[["render",o]]);export{g as __pageData,u as default};
